        $user_id = wp_insert_user([
            'user_login' => $username,
            'user_email' => $email,
            'user_pass'  => $hashed_password,
            'role'       => get_option('default_role', 'subscriber'),
        ]);

        if (is_wp_error($user_id)) {
            $this->safe_redirect(add_query_arg('sua_register', 'error', $this->get_current_url()));
        }

        $this->safe_redirect(add_query_arg('sua_register', 'success', $this->get_current_url()));
    }

    public function handle_login() {
