        $identifier = isset($_POST['sua_login_identifier']) ? sanitize_text_field(wp_unslash($_POST['sua_login_identifier'])) : '';
        $password = isset($_POST['sua_login_password']) ? (string) wp_unslash($_POST['sua_login_password']) : '';

        if (empty($identifier) || empty($password)) {
